  assign fifo_rd_dout = 'h0;
  assign fifo_rd_underflow = 1'b0;
  assign fifo_rd_xfer_req = 1'b0;

  end endgenerate

  generate if (DMA_TYPE_SRC == DMA_TYPE_MM_AXI) begin

